const { gameState, checkGameStatus, resetGame, winningCombinations } = require('./game.js');

let testsPassed = 0;
let testsFailed = 0;

// assert 함수
function assert(condition, testName) {
    if (condition) {
        console.log(`✅ ${testName}`);
        testsPassed++;
    } else {
        console.log(`❌ ${testName}`);
        testsFailed++;
    }
}

// 게임판 상태 설정 헬퍼
function setBoard(state) {
    gameState.board = [...state];
}

// 테스트: 가로 승리 감지
function testRowWin() {
    console.log('\n=== 가로 승리 감지 ===');

    // 첫 번째 행 X 승리
    setBoard(['X', 'X', 'X', '', '', '', '', '', '']);
    let result = checkGameStatus();
    assert(result.winner === 'X' && result.winningCells.length === 3, '첫 번째 행: X 승리');

    // 두 번째 행 O 승리
    setBoard(['', '', '', 'O', 'O', 'O', '', '', '']);
    result = checkGameStatus();
    assert(result.winner === 'O' && result.winningCells.length === 3, '두 번째 행: O 승리');

    // 세 번째 행 X 승리
    setBoard(['', '', '', '', '', '', 'X', 'X', 'X']);
    result = checkGameStatus();
    assert(result.winner === 'X' && result.winningCells.length === 3, '세 번째 행: X 승리');
}

// 테스트: 세로 승리 감지
function testColumnWin() {
    console.log('\n=== 세로 승리 감지 ===');

    // 첫 번째 열 X 승리
    setBoard(['X', '', '', 'X', '', '', 'X', '', '']);
    let result = checkGameStatus();
    assert(result.winner === 'X', '첫 번째 열: X 승리');

    // 두 번째 열 O 승리
    setBoard(['', 'O', '', '', 'O', '', '', 'O', '']);
    result = checkGameStatus();
    assert(result.winner === 'O', '두 번째 열: O 승리');

    // 세 번째 열 X 승리
    setBoard(['', '', 'X', '', '', 'X', '', '', 'X']);
    result = checkGameStatus();
    assert(result.winner === 'X', '세 번째 열: X 승리');
}

// 테스트: 대각선 승리 감지
function testDiagonalWin() {
    console.log('\n=== 대각선 승리 감지 ===');

    // 왼쪽 위부터 오른쪽 아래 대각선 X 승리
    setBoard(['X', '', '', '', 'X', '', '', '', 'X']);
    let result = checkGameStatus();
    assert(result.winner === 'X', '좌상향-우하향 대각선: X 승리');

    // 오른쪽 위부터 왼쪽 아래 대각선 O 승리
    setBoard(['', '', 'O', '', 'O', '', 'O', '', '']);
    result = checkGameStatus();
    assert(result.winner === 'O', '우상향-좌하향 대각선: O 승리');
}

// 테스트: 무승부 감지
function testDrawDetection() {
    console.log('\n=== 무승부 감지 ===');

    // 모든 칸이 차 있지만 승리자 없음
    const drawBoard = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', 'O'];
    setBoard(drawBoard);
    let result = checkGameStatus();
    assert(result.isDraw === true && result.winner === null, '무승부 상황 감지');

    // 게임판이 가득 차지 않으면 무승부가 아님
    setBoard(['X', 'O', '', 'O', 'X', '', '', '', '']);
    result = checkGameStatus();
    assert(result.isDraw === false, '게임판이 덜 찼을 때 무승부가 아님');
}

// 테스트: 게임 초기화
function testReset() {
    console.log('\n=== 게임 초기화 ===');

    // 게임판을 임의로 설정
    gameState.board = ['X', 'O', 'X', 'O', 'X', '', '', '', ''];
    gameState.currentPlayer = 'O';
    gameState.isGameOver = true;
    gameState.winner = 'X';

    // 초기화 실행
    resetGame();

    assert(
        gameState.board.every(cell => cell === '') &&
        gameState.currentPlayer === 'X' &&
        gameState.isGameOver === false &&
        gameState.winner === null,
        '게임 상태 완전 초기화'
    );
}

// 테스트: 턴 전환 로직
function testTurnSwitching() {
    console.log('\n=== 턴 전환 ===');

    resetGame();
    assert(gameState.currentPlayer === 'X', '초기 플레이어: X');

    // 플레이어 전환 로직 테스트
    gameState.currentPlayer = gameState.currentPlayer === 'X' ? 'O' : 'X';
    assert(gameState.currentPlayer === 'O', 'X에서 O로 전환');

    gameState.currentPlayer = gameState.currentPlayer === 'X' ? 'O' : 'X';
    assert(gameState.currentPlayer === 'X', 'O에서 X로 전환');
}

// 테스트: 승리 조합 정의
function testWinningCombinations() {
    console.log('\n=== 승리 조합 정의 ===');

    assert(winningCombinations.length === 8, '8가지 승리 조합 정의');
    assert(
        winningCombinations.some(combo => JSON.stringify(combo) === JSON.stringify([0, 1, 2])),
        '첫 번째 행 조합 존재'
    );
    assert(
        winningCombinations.some(combo => JSON.stringify(combo) === JSON.stringify([0, 4, 8])),
        '왼쪽 위에서 오른쪽 아래 대각선 조합 존재'
    );
}

// 테스트: 빈 게임판에서는 승리자 없음
function testEmptyBoard() {
    console.log('\n=== 빈 게임판 ===');

    setBoard(['', '', '', '', '', '', '', '', '']);
    const result = checkGameStatus();
    assert(
        result.winner === null && result.isDraw === false,
        '빈 게임판에는 승리자 없음'
    );
}

// 모든 테스트 실행
console.log('🎮 틱택토 게임 테스트 시작\n');
testRowWin();
testColumnWin();
testDiagonalWin();
testDrawDetection();
testReset();
testTurnSwitching();
testWinningCombinations();
testEmptyBoard();

// 테스트 결과 요약
console.log('\n=============================');
console.log(`총 ${testsPassed + testsFailed}개 테스트 중`);
console.log(`✅ 통과: ${testsPassed}개`);
console.log(`❌ 실패: ${testsFailed}개`);
console.log('=============================\n');

if (testsFailed === 0) {
    console.log('🎉 모든 테스트 통과했습니다!\n');
    process.exit(0);
} else {
    console.log(`⚠️  ${testsFailed}개 테스트 실패\n`);
    process.exit(1);
}

