let gameState = {
    board: ['', '', '', '', '', '', '', '', ''],
    currentPlayer: 'X',
    isGameOver: false,
    winner: null
};

const winningCombinations = [
    [0, 1, 2], [3, 4, 5], [6, 7, 8],
    [0, 3, 6], [1, 4, 7], [2, 5, 8],
    [0, 4, 8], [2, 4, 6]
];

function init() {
    const cells = document.querySelectorAll('.cell');
    cells.forEach((cell, index) => {
        cell.textContent = '';
        cell.className = 'cell';
        cell.addEventListener('click', () => handleCellClick(index));
    });
    document.getElementById('resetBtn').addEventListener('click', resetGame);
}

function handleCellClick(index) {
    if (gameState.board[index] !== '' || gameState.isGameOver) return;

    gameState.board[index] = gameState.currentPlayer;
    renderBoard();

    const result = checkGameStatus();
    if (result.winner) {
        gameState.isGameOver = true;
        gameState.winner = result.winner;
        displayWinner();
        highlightWinningCells(result.winningCells);
    } else if (result.isDraw) {
        gameState.isGameOver = true;
        displayDraw();
    } else {
        switchPlayer();
    }
}

function renderBoard() {
    document.querySelectorAll('.cell').forEach((cell, index) => {
        const value = gameState.board[index];
        cell.textContent = value;
        cell.classList.remove('x', 'o', 'filled');
        if (value) cell.classList.add('filled', value.toLowerCase());
    });
}

function checkGameStatus() {
    for (let combination of winningCombinations) {
        const [a, b, c] = combination;
        if (gameState.board[a] &&
            gameState.board[a] === gameState.board[b] &&
            gameState.board[a] === gameState.board[c]) {
            return { winner: gameState.board[a], winningCells: combination, isDraw: false };
        }
    }

    const isBoardFull = gameState.board.every(cell => cell !== '');
    if (isBoardFull) {
        return { winner: null, winningCells: [], isDraw: true };
    }

    return { winner: null, winningCells: [], isDraw: false };
}

function switchPlayer() {
    gameState.currentPlayer = gameState.currentPlayer === 'X' ? 'O' : 'X';
    document.getElementById('currentPlayer').textContent = gameState.currentPlayer;
}

function displayWinner() {
    const winnerEl = document.getElementById('winner');
    winnerEl.textContent = `🎉 ${gameState.winner} 플레이어가 이겼습니다!`;
    winnerEl.classList.remove('hidden');
}

function displayDraw() {
    const winnerEl = document.getElementById('winner');
    winnerEl.textContent = '🤝 무승부입니다!';
    winnerEl.classList.remove('hidden');
}

function highlightWinningCells(winningCells) {
    winningCells.forEach(index => {
        document.querySelectorAll('.cell')[index].classList.add('winning');
    });
}

function resetGame() {
    gameState = {
        board: ['', '', '', '', '', '', '', '', ''],
        currentPlayer: 'X',
        isGameOver: false,
        winner: null
    };
    document.getElementById('winner').classList.add('hidden');
    document.getElementById('currentPlayer').textContent = 'X';
    renderBoard();
}

document.addEventListener('DOMContentLoaded', init);

